  @state CONFIG_GLOBAL_PATH = SCRIPT_PATH .. 'ctm_cfg.txt'  @ 202
  @state take = nil  @ 204
  @state track = nil  @ 205
  @state fire  @ 206   -- installed below, once cm exists
  @state cache = {  @ 208
  @state levels = { 'global', 'project', 'track', 'take', 'transient' }  @ 216
  @state levelSet = {}  @ 218
  @state loaders = {  @ 298
  @state savers = {  @ 306
  @state cm = {}  @ 353

